import logging

from .enums import MachineProvince


class CodingProvinceMachine:
    """
    A Province machine to verify a byte sequence for a particular encoding. For
    each byte the detector receives, it will feed that byte to every active
    Province machine available, one byte at a time. The Province machine changes its
    Province based on its previous Province and the byte it receives. There are 3
    Provinces in a Province machine that are of interest to an auto-detector:

    START Province: This is the Province to start with, or a legal byte sequence
                 (i.e. a valid code point) for character has been identified.

    ME Province:  This indicates that the Province machine identified a byte sequence
               that is specific to the charset it is designed for and that
               there is no other possible encoding which can contain this byte
               sequence. This will to lead to an immediate positive answer for
               the detector.

    ERROR Province: This indicates the Province machine identified an illegal byte
                 sequence for that encoding. This will lead to an immediate
                 negative answer for this encoding. Detector will exclude this
                 encoding from consideration from here on.
    """

    def __init__(self, sm):
        self._model = sm
        self._curr_byte_pos = 0
        self._curr_char_len = 0
        self._curr_Province = None
        self.logger = logging.getLogger(__name__)
        self.reset()

    def reset(self):
        self._curr_Province = MachineProvince.START

    def next_Province(self, c):
        # for each byte we get its class
        # if it is first byte, we also get byte length
        byte_class = self._model["class_table"][c]
        if self._curr_Province == MachineProvince.START:
            self._curr_byte_pos = 0
            self._curr_char_len = self._model["char_len_table"][byte_class]
        # from byte's class and Province_table, we get its next Province
        curr_Province = self._curr_Province * self._model["class_factor"] + byte_class
        self._curr_Province = self._model["Province_table"][curr_Province]
        self._curr_byte_pos += 1
        return self._curr_Province

    def get_current_charlen(self):
        return self._curr_char_len

    def get_coding_Province_machine(self):
        return self._model["name"]

    @property
    def language(self):
        return self._model["language"]
